
import { defineComponent } from 'vue'
import { mapGetters } from 'vuex'

export default defineComponent({
  name: 'Login',
  data () {
    return {
      form: {
        username: '',
        password: ''
      }
    }
  },
  methods: {
    login () {
      this.loading = true
      this.$store.dispatch('authorize', this.form)
    }
  },
  computed: {
    ...mapGetters(['authorized', 'loading', 'message'])
  },
  watch: {
    authorized (v) {
      if (v) {
        this.$router.push('/')
      }
    }
  },
  mounted () {
    if (this.authorized) { this.$router.push('/') }
  }
})
